# Vulnerable pattern: tool uses the agent's own credentials
# and accepts any caller-supplied argument without verification

class VulnerableOrderTool:
    def __init__(self, db_conn):
        self._db = db_conn  # agent's DB connection — can query all orders

    def get_order(self, order_id: str) -> dict:
        # No check: who is the caller? Are they allowed to see this order?
        return self._db.execute(
            "SELECT * FROM orders WHERE id = ?", (order_id,)
        ).fetchone()

# A user who knows order IDs can read any order.

# Fixed pattern: pass caller identity and enforce at the resource boundary

from dataclasses import dataclass

@dataclass(frozen=True)
class CallerContext:
    user_id: str
    customer_id: str
    roles: frozenset[str]
    session_id: str

class SecureOrderTool:
    def __init__(self, db_conn):
        self._db = db_conn

    def get_order(self, order_id: str, caller: CallerContext) -> dict:
        # Fetch the order
        row = self._db.execute(
            "SELECT * FROM orders WHERE id = ?", (order_id,)
        ).fetchone()
        if row is None:
            raise KeyError(f"Order {order_id!r} not found")

        # Verify caller is entitled to see this order
        if row["customer_id"] != caller.customer_id:
            if "support_agent" not in caller.roles:  # support staff can see all orders
                raise PermissionError(
                    f"Caller {caller.user_id!r} (customer {caller.customer_id!r}) "
                    f"is not authorised to access order {order_id!r}"
                )
        return dict(row)

import pytest

@pytest.fixture
def tool(db_connection):
    return SecureOrderTool(db_connection)

@pytest.fixture
def alice():
    return CallerContext("alice", "cust-001", frozenset(), "sess-1")

@pytest.fixture
def bob():
    return CallerContext("bob", "cust-002", frozenset(), "sess-2")

def test_own_order_accessible(tool, alice, seed_order_for_cust001):
    result = tool.get_order(seed_order_for_cust001, caller=alice)
    assert result["customer_id"] == "cust-001"

def test_cross_customer_blocked(tool, bob, seed_order_for_cust001):
    with pytest.raises(PermissionError, match="not authorised"):
        tool.get_order(seed_order_for_cust001, caller=bob)

def test_support_agent_can_access_any(tool, seed_order_for_cust001):
    support = CallerContext("eve", "cust-000", frozenset({"support_agent"}), "sess-3")
    result = tool.get_order(seed_order_for_cust001, caller=support)
    assert result is not None

from dataclasses import dataclass

@dataclass(frozen=True)
class TenantContext:
    tenant_id: str
    user_id: str

class TenantScopedRetriever:
    def __init__(self, vector_store, tenant: TenantContext):
        self._store = vector_store
        self._tenant = tenant

    def retrieve(self, query: str, top_k: int = 5) -> list[dict]:
        """
        Every retrieval query is filtered to the tenant's namespace.
        Cross-tenant retrieval is structurally impossible.
        """
        results = self._store.search(
            query,
            filter={"tenant_id": self._tenant.tenant_id},
            top_k=top_k,
        )
        # Double-check at the application layer (belt-and-suspenders)
        for r in results:
            if r["metadata"]["tenant_id"] != self._tenant.tenant_id:
                raise RuntimeError(
                    f"Vector store returned cross-tenant result: "
                    f"{r['metadata']['tenant_id']!r} != {self._tenant.tenant_id!r}"
                )
        return results

from dataclasses import dataclass, field
from enum import auto, Enum

class TaskScope(Enum):
    CATALOGUE_SEARCH   = auto()
    ORDER_SUPPORT      = auto()
    ACCOUNT_MANAGEMENT = auto()

TASK_ALLOWED_TOOLS: dict[TaskScope, frozenset[str]] = {
    TaskScope.CATALOGUE_SEARCH:   frozenset({"search_catalogue", "get_product_detail"}),
    TaskScope.ORDER_SUPPORT:      frozenset({"get_order_status", "submit_refund"}),
    TaskScope.ACCOUNT_MANAGEMENT: frozenset({"get_profile", "update_email"}),
}

@dataclass
class TurnContext:
    caller: "CallerContext"
    current_task: TaskScope
    session_history: list[str] = field(default_factory=list)

class ScopedDispatcher:
    def dispatch(self, tool_name: str, args: dict, turn: TurnContext) -> any:
        allowed = TASK_ALLOWED_TOOLS.get(turn.current_task, frozenset())
        if tool_name not in allowed:
            raise PermissionError(
                f"Tool '{tool_name}' is not in scope for task "
                f"{turn.current_task.name!r}. "
                f"Allowed: {sorted(allowed)}"
            )
        # Proceed with caller-aware dispatch
        return self._execute(tool_name, args, caller=turn.caller)

    def _execute(self, tool_name, args, caller): ...
